const z2ui5_cl_util = require("abap2UI5/z2ui5_cl_util");
const z2ui5_cl_xml_view = require("abap2UI5/z2ui5_cl_xml_view");
const z2ui5_if_app = require("abap2UI5/z2ui5_if_app");

class z2ui5_cl_demo_app_296 extends z2ui5_if_app {
  client = null;

  view_display({ client } = {}) {
    const page_01 = z2ui5_cl_xml_view.factory()
      .shell()
      .page({ title: `abap2UI5 - Sample: Search Field`, navbuttonpress: client._event_nav_app_leave(), shownavbutton: client.check_app_prev_stack() });
    page_01.header_content()
      .button({ id: `button_hint_id`, icon: `sap-icon://hint`, tooltip: `Sample information`, press: client._event(`CLICK_HINT_ICON`) });
    page_01.header_content()
      .link({ text: `UI5 Demo Kit`, target: `_blank`, href: `https://sapui5.hana.ondemand.com/sdk/#/entity/sap.m.SearchField/sample/sap.m.sample.SearchField` });
    page_01.page({ showheader: false })
      .sub_header()
      .toolbar()
      .search_field({ width: `100%`, search: client._event(`onSearch`, [`\${$parameters>/searchButtonPressed}`]) })
      .text({ text: `Default Search`, id: `idSearchListToolbar` })
      .get_parent()
      .get_parent()
      .vbox(`sapUiSmallMargin`)
      .label(`Default Search Field:`)
      .search_field({ width: `90%`, class: `sapUiSmallMargin` })
      .get_parent();
    client.view_display(page_01.stringify());
  }

  on_event({ client } = {}) {
    switch (client.get().EVENT) {
      case `CLICK_HINT_ICON`:
        this.popover_display({ id: `button_hint_id` });
        break;
      case `onSearch`:
        if (client.get_event_arg() === `true`) {
          client.message_toast_display(`'search' event fired with 'searchButtonPressed' parameter`);
        }
        break;
    }
  }

  popover_display({ id } = {}) {
    const view = z2ui5_cl_xml_view.factory_popup();
    view.quick_view({ placement: `Bottom`, width: `auto` })
      .quick_view_page({ pageid: `sampleInformationId`, header: `Sample information`, description: `Use the Search Field to let the user enter a search string and trigger the search process.` });
    this.client.popover_display(view.stringify(), id);
  }

  async main(client) {
    this.client = z2ui5_cl_util.abap_copy(client);
    if (client.check_on_init()) {
      this.view_display({ client: client });
    }
    this.on_event({ client: client });
  }
}

module.exports = z2ui5_cl_demo_app_296;
